import React, { useState } from "react";
import Navbar from "../Pages/Navbar";
import {
  Box,
  Button,
  Flex,
  Heading,
  Input,
  Spinner,
  Text,
  useToast,
  FormControl,
  FormLabel,
} from "@chakra-ui/react";
import { AiOutlineEyeInvisible, AiFillEye } from "react-icons/ai";
import { useDispatch, useSelector } from "react-redux";
import { Link, useNavigate } from "react-router-dom";
import { signUpFetch } from "../Redux/UserReducer/action";
import { actionsingUpError } from "../Redux/UserReducer/actionType";

export const showToast = (toast, title, status = "success") => {
  toast({
    title,
    status,
    duration: 3000,
    isClosable: true,
  });
};
const SignUp = () => {
  const [form, setForm] = useState({
    email: "",
    password: "",
    confirmPassword: "",
    name: "",
    isPromotion: false,
  });

  const [showPassword, setShowPassword] = useState(false);

  const navigate = useNavigate();
  const userStore = useSelector((store) => store.UserReducer);
  const dispatch = useDispatch();
  const toast = useToast();

  const handleInput = (e) => {
    const { name, value } = e.target;
    setForm({ ...form, [name]: value });
  };

  const handleSignUp = async () => {
    const { email, password, confirmPassword, name } = form;

    if (!email || !password || !confirmPassword || !name) {
      dispatch(actionsingUpError("All fields are required"));
      return;
    }

    if (password !== confirmPassword) {
      dispatch(actionsingUpError("Passwords do not match"));
      return;
    }

    if (password.length < 8) {
      dispatch(actionsingUpError("Password must be at least 8 characters"));
      return;
    }

    dispatch(signUpFetch(form)).then(() => {
      if (!userStore?.isError) {
        showToast({ toast, message: "Sign up successful", color: "green" });
        navigate("/login");
      } else {
        showToast({ toast, message: userStore?.isError, color: "red" });
      }
    });
  };

  return (
    <Box bg="#f7f9fa" minH="100vh">
      <Navbar />

      <Flex justify="center" align="center" py={10}>
        <Box
          bg="white"
          p={8}
          borderRadius="lg"
          boxShadow="lg"
          w={{ base: "90%", md: "400px" }}
        >
          <Heading size="md" mb={6}>
            Sign up and start learning
          </Heading>

          {/* Name */}
          <FormControl mb={4}>
            <FormLabel>Name</FormLabel>
            <Input
              name="name"
              value={form.name}
              onChange={handleInput}
              border="1px solid #d1d7dc"
              _focus={{
                borderColor: "#A435F0",
                boxShadow: "0 0 0 1px #A435F0",
              }}
            />
          </FormControl>

          {/* Email */}
          <FormControl mb={4}>
            <FormLabel>Email</FormLabel>
            <Input
              name="email"
              value={form.email}
              onChange={handleInput}
              border="1px solid #d1d7dc"
              _focus={{
                borderColor: "#A435F0",
                boxShadow: "0 0 0 1px #A435F0",
              }}
            />
          </FormControl>

          {/* Password */}
          <FormControl mb={4}>
            <FormLabel>Password</FormLabel>
            <Flex>
              <Input
                type={showPassword ? "text" : "password"}
                name="password"
                value={form.password}
                onChange={handleInput}
                border="1px solid #d1d7dc"
                _focus={{
                  borderColor: "#A435F0",
                  boxShadow: "0 0 0 1px #A435F0",
                }}
              />
              <Box
                ml={2}
                display="flex"
                alignItems="center"
                cursor="pointer"
                onClick={() => setShowPassword(!showPassword)}
              >
                {showPassword ? <AiFillEye /> : <AiOutlineEyeInvisible />}
              </Box>
            </Flex>
          </FormControl>

          {/* Confirm Password */}
          <FormControl mb={6}>
            <FormLabel>Confirm Password</FormLabel>
            <Input
              type="password"
              name="confirmPassword"
              value={form.confirmPassword}
              onChange={handleInput}
              border="1px solid #d1d7dc"
              _focus={{
                borderColor: "#A435F0",
                boxShadow: "0 0 0 1px #A435F0",
              }}
            />
          </FormControl>

          {/* Button */}
          <Button
            w="100%"
            bg="#A435F0"
            color="white"
            _hover={{ bg: "#8710d8" }}
            onClick={handleSignUp}
          >
            {userStore.loading ? <Spinner /> : "Sign Up"}
          </Button>

          {/* Login */}
          <Text mt={4} fontSize="sm">
            Already have an account?{" "}
            <Link to="/login">
              <Text as="span" color="#A435F0" fontWeight="600">
                Log in
              </Text>
            </Link>
          </Text>
        </Box>
      </Flex>
    </Box>
  );
};

export default SignUp;
